const rawText = $input.first().json.message?.text || '';
const semComando = rawText.replace(/^\/clima\s*/i, '').trim();
const semAcento = semComando.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const limpo = semAcento.replace(/\s*,\s*/g, ',').replace(/\s+/g, ' ').trim().toLowerCase();
const ufsBrasil = ['ac','al','ap','am','ba','ce','df','es','go','ma','mt','ms','mg','pa','pb','pr','pe','pi','rj','rn','rs','ro','rr','sc','sp','se','to'];
let queue = limpo;
if (limpo.includes(',')) {
  const [cidade, uf] = limpo.split(',').map(v => v.trim());
  if (cidade && uf) {
    if (ufsBrasil.includes(uf)) queue = `${cidade},br`;
    else queue = `${cidade},${uf}`;
  }
}
return [{ json: { queue, original_input: semComando, chat_id: $input.first().json.message.chat.id } }];

const data = $input.first().json;
const cidade = data.name;
const temp = Math.round(data.main.temp);
const message = `🌤️ A temperatura em ${cidade} é de ${temp}°C.`;
return [{ json: { ok: true, message, chat_id: $('Extrair Cidade').first().json.chat_id } }];

const fallback = $('Code Fallback').first().json;
let finalMessage = fallback.message;
try {
  const ai = $input.first().json;
  const candidates = [ai.output, ai.text, ai.message, ai.response, ai.content, ai.result, ai.data?.output, ai.data?.text];
  for (const candidate of candidates) {
    if (!candidate) continue;
    if (typeof candidate === 'string') {
      try {
        const parsed = JSON.parse(candidate);
        if (parsed?.message) {
          finalMessage = parsed.message;
          break;
        }
      } catch (e) {
        if (candidate.trim()) {
          finalMessage = candidate.trim();
          break;
        }
      }
    } else if (candidate?.message) {
      finalMessage = candidate.message;
      break;
    }
  }
} catch (e) {}
return [{ json: { ok: true, message: finalMessage, chat_id: fallback.chat_id } }];
